const output = $json.output || "";

// Remove markdown (**)
const cleanOutput = output.replace(/\*\*/g, "");

// Convert sections to HTML
const formatted = cleanOutput
  .replace(/Summary:/gi, "<b>Summary:</b><br>")
  .replace(/Key Highlights:/gi, "<b>Key Highlights:</b><br>")
  .replace(/Risk Analysis:/gi, "<b>Risk Analysis:</b><br>")
  .replace(/Future Outlook:/gi, "<b>Future Outlook:</b><br>")
  .replace(/\n/g, "<br>");

// Final HTML
const formattedReport = `
<div>
  <p>${formatted}</p>
</div>
`;

return [
  {
    json: {
      ...$json,   
      formattedReport
    }
  }
];

const invested = Number($json["Invested"] || 0);
const current = Number($json["Current Value"] || 0);

const profit = current - invested;

const growth = invested > 0
  ? ((profit / invested) * 100).toFixed(2)
  : 0;

return [
  {
    json: {
      ...$json,   // keep original data (Email, Client)
      totalInvested: invested,
      totalCurrent: current,
      profit,
      growth
    }
  }
];

return items.map(item => {
